	@Test
	public void testCalibrationAdjustsEstimateEnvelope() {
		EvaluationStatistics.clearCalibrationObservations();
		try {
			EvaluationStatistics statistics = new EvaluationStatistics();
			EvaluationStatistics.CardinalityEstimate baseline = statistics
					.getCardinalityEstimate(new StatementPattern(Var.of("a"), Var.of("b"), Var.of("c")));
			EvaluationStatistics.recordGlobalCardinalityObservation("legacy", baseline.estimate,
					baseline.estimate * 8.0);

			EvaluationStatistics.CardinalityEstimate calibrated = statistics
					.getCardinalityEstimate(new StatementPattern(Var.of("x"), Var.of("y"), Var.of("z")));
			EvaluationStatistics.CalibrationSnapshot snapshot = EvaluationStatistics.getCalibrationSnapshot("legacy");

			assertThat(snapshot).isNotNull();
			assertThat(snapshot.sampleCount).isGreaterThan(0);
			assertThat(calibrated.confidence).isLessThan(baseline.confidence);
			assertThat(calibrated.lowerBound).isLessThanOrEqualTo(baseline.lowerBound);
			assertThat(calibrated.upperBound).isGreaterThanOrEqualTo(baseline.upperBound);
		} finally {
			EvaluationStatistics.clearCalibrationObservations();
		}
	}

